(window.webpackJsonp=window.webpackJsonp||[]).push([[668],{643:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">grid</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">k</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[][]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> shiftGrid = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">grid, k</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> r=grid.length\\n  <span class=\\"hljs-keyword\\">let</span> c=grid[<span class=\\"hljs-number\\">0</span>].length\\n  <span class=\\"hljs-keyword\\">let</span> all=r*c\\n  k= k % all\\n  <span class=\\"hljs-keyword\\">let</span> newR=~~(k / c)\\n  <span class=\\"hljs-keyword\\">let</span> newC=k % c\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-built_in\\">Array</span>(r).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span><span class=\\"hljs-built_in\\">Array</span>(c).fill(<span class=\\"hljs-literal\\">null</span>))\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;r;i++){\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;c;j++){\\n      <span class=\\"hljs-comment\\">// console.log(newR,newC)</span>\\n      res[newR][newC]=grid[i][j]\\n      newC++\\n      <span class=\\"hljs-keyword\\">if</span>(newC===c){\\n        newC=<span class=\\"hljs-number\\">0</span>\\n        newR++\\n      }\\n      <span class=\\"hljs-keyword\\">if</span>(newR===r){\\n        newR=<span class=\\"hljs-number\\">0</span>\\n        newC=<span class=\\"hljs-number\\">0</span>\\n      }\\n      <span class=\\"hljs-comment\\">// console.log(res[newR][newC])</span>\\n      <span class=\\"hljs-keyword\\">if</span>(res[newR][newC]!=<span class=\\"hljs-literal\\">null</span>)<span class=\\"hljs-keyword\\">return</span> res\\n    }\\n  }\\n \\n};\\n</code></pre>\\n"],"titleSlug":"shift-2d-grid","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a <code>m</code> \u884c <code>n</code>\xa0\u5217\u7684\u4e8c\u7ef4\u7f51\u683c\xa0<code>grid</code>\xa0\u548c\u4e00\u4e2a\u6574\u6570\xa0<code>k</code>\u3002\u4f60\u9700\u8981\u5c06\xa0<code>grid</code>\xa0\u8fc1\u79fb\xa0<code>k</code>\xa0\u6b21\u3002</p>\\n\\n<p>\u6bcf\u6b21\u300c\u8fc1\u79fb\u300d\u64cd\u4f5c\u5c06\u4f1a\u5f15\u53d1\u4e0b\u8ff0\u6d3b\u52a8\uff1a</p>\\n\\n<ul>\\n\\t<li>\u4f4d\u4e8e <code>grid[i][j]</code>\xa0\u7684\u5143\u7d20\u5c06\u4f1a\u79fb\u52a8\u5230\xa0<code>grid[i][j + 1]</code>\u3002</li>\\n\\t<li>\u4f4d\u4e8e\xa0<code>grid[i][n\xa0- 1]</code> \u7684\u5143\u7d20\u5c06\u4f1a\u79fb\u52a8\u5230\xa0<code>grid[i + 1][0]</code>\u3002</li>\\n\\t<li>\u4f4d\u4e8e <code>grid[m\xa0- 1][n - 1]</code>\xa0\u7684\u5143\u7d20\u5c06\u4f1a\u79fb\u52a8\u5230\xa0<code>grid[0][0]</code>\u3002</li>\\n</ul>\\n\\n<p>\u8bf7\u4f60\u8fd4\u56de\xa0<code>k</code> \u6b21\u8fc1\u79fb\u64cd\u4f5c\u540e\u6700\u7ec8\u5f97\u5230\u7684 <strong>\u4e8c\u7ef4\u7f51\u683c</strong>\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/11/16/e1-1.png\\" style=\\"height: 158px; width: 400px;\\" /></p>\\n\\n<pre>\\n<code><strong>\u8f93\u5165\uff1a</strong>grid</code> = [[1,2,3],[4,5,6],[7,8,9]], k = 1\\n<strong>\u8f93\u51fa\uff1a</strong>[[9,1,2],[3,4,5],[6,7,8]]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/11/16/e2-1.png\\" style=\\"height: 166px; width: 400px;\\" /></p>\\n\\n<pre>\\n<code><strong>\u8f93\u5165\uff1a</strong>grid</code> = [[3,8,1,9],[19,7,2,5],[4,6,11,10],[12,0,21,13]], k = 4\\n<strong>\u8f93\u51fa\uff1a</strong>[[12,0,21,13],[3,8,1,9],[19,7,2,5],[4,6,11,10]]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<code><strong>\u8f93\u5165\uff1a</strong>grid</code> = [[1,2,3],[4,5,6],[7,8,9]], k = 9\\n<strong>\u8f93\u51fa\uff1a</strong>[[1,2,3],[4,5,6],[7,8,9]]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>m ==\xa0grid.length</code></li>\\n\\t<li><code>n ==\xa0grid[i].length</code></li>\\n\\t<li><code>1 <= m <= 50</code></li>\\n\\t<li><code>1 <= n <= 50</code></li>\\n\\t<li><code>-1000 <= grid[i][j] <= 1000</code></li>\\n\\t<li><code>0 <= k <= 100</code></li>\\n</ul>\\n","title":"1260. \u4e8c\u7ef4\u7f51\u683c\u8fc1\u79fb","relatedTags":["\u6570\u7ec4"],"difficult":"Easy","lang":["javascript"],"uniqueID":"1260"}')}}]);